const LANG = {
    en: { search: 'Search', download: 'Download', error: 'Error' },
    zh: { search: '搜索', download: '下载', error: '错误' },
    ja: { search: '検索', download: 'ダウンロード', error: 'エラー' }
};
let currentLang = localStorage.getItem('lang') || 'en';
function t(key) { return LANG[currentLang]?.[key] || LANG.en[key] || key; }

function applyTranslations() {
    document.querySelectorAll('[data-i18n]').forEach(el => {
        el.textContent = t(el.dataset.i18n);
    });
    document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
        el.placeholder = t(el.dataset.i18nPlaceholder);
    });
}
// HTML: <button data-i18n="search">Search</button>

function escapeHtml(str) {
    const div = document.createElement('div');
    div.appendChild(document.createTextNode(str));
    return div.innerHTML;
}
function escapeAttr(str) {
    return String(str).replace(/&/g,'&amp;').replace(/'/g,'&#39;')
        .replace(/\x22/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

const MAX_HISTORY = 30;
function addToHistory(item) {
    let history = JSON.parse(localStorage.getItem('app-history') || '[]');
    history = history.filter(h => h.id !== item.id);  // Deduplicate
    history.unshift(item);  // Newest first
    if (history.length > MAX_HISTORY) history = history.slice(0, MAX_HISTORY);
    localStorage.setItem('app-history', JSON.stringify(history));
}

function loadSettings() {
    return {
        folder: localStorage.getItem('app-folder') || '',
        lang: localStorage.getItem('app-lang') || 'en',
        quality: localStorage.getItem('app-quality') || '720'
    };
}
function saveSetting(key, value) {
    localStorage.setItem(`app-${key}`, value);
}

// Cache at top of file — avoid repeated getElementById
const searchInput = document.getElementById('search-input');
const searchBtn = document.getElementById('search-btn');
const resultsList = document.getElementById('results-list');
const errorMsg = document.getElementById('error-msg');

// WRONG (Windows backslash breaks inline onclick):
html += `<div onclick="openFolder('C:\Users\...')">Open</div>`;

// CORRECT:
html += `<div class="folder-btn" data-path="${escapeAttr(path)}">Open</div>`;
document.addEventListener('click', (e) => {
    const btn = e.target.closest('.folder-btn');
    if (btn) openFolder(btn.dataset.path);
});

async function handleSubmit() {
    const btn = document.getElementById('submit-btn');
    btn.disabled = true;
    btn.textContent = t('processing');
    try {
        const result = await doAsyncWork();
        showSuccess(result);
    } catch (err) {
        showError(err.message);
    } finally {
        btn.disabled = false;
        btn.textContent = t('submit');
    }
}

