/* CSS */
.hidden { display: none !important; }

/* JS */
el.classList.add('hidden');    // Hide
el.classList.remove('hidden'); // Show
el.classList.toggle('hidden'); // Toggle

async function apiPost(endpoint, data) {
    try {
        const res = await fetch(endpoint, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify(data)
        });
        const json = await res.json();
        if (!res.ok) {
            showError(json.error || `Error ${res.status}`);
            return null;
        }
        return json;
    } catch (err) {
        showError(t('network_error'));
        return null;
    }
}

function showError(msg, duration = 5000) {
    const el = document.getElementById('error-msg');
    el.textContent = msg;
    el.classList.remove('hidden');
    if (duration > 0) {
        setTimeout(() => el.classList.add('hidden'), duration);
    }
}

/* Hover effects */
.btn { transition: all 0.2s ease; }
.card { transition: border-color 0.15s; }
.progress { transition: width 0.3s ease; }

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
    * { transition-duration: 0.01ms !important; }
}

/* Mobile first */
.container { padding: 1rem; }

/* Tablet */
@media (min-width: 768px) {
    .container { padding: 2rem; }
}

/* Desktop 3-column */
@media (min-width: 1024px) {
    .layout { display: grid; grid-template-columns: 300px 1fr 280px; }
}

/* Single column on mobile */
@media (max-width: 1024px) {
    .layout { grid-template-columns: 1fr; }
}

async function browseFolder() {
    const data = await apiPost('/api/browse-folder', {});
    if (data && data.folder) {
        document.getElementById('folder-path').value = data.folder;
        localStorage.setItem('app-folder', data.folder);
    }
}

function trackProgress(taskId) {
    const es = new EventSource(`/api/progress/${taskId}`);
    es.onmessage = (e) => {
        const data = JSON.parse(e.data);
        updateProgressBar(data.percent);
        if (data.status === 'done' || data.status === 'error') {
            es.close();
            if (data.status === 'done') onComplete(data);
            else showError(data.error);
        }
    };
    es.onerror = () => { es.close(); showError(t('connection_lost')); };
}

function debounce(fn, delay = 500) {
    let timer;
    return (...args) => {
        clearTimeout(timer);
        timer = setTimeout(() => fn(...args), delay);
    };
}

searchInput.addEventListener('input', debounce((e) => {
    performSearch(e.target.value);
}, 500));

document.addEventListener('keydown', (e) => {
    // Ctrl+Enter to submit
    if (e.ctrlKey && e.key === 'Enter') {
        e.preventDefault();
        handleSubmit();
    }
    // Escape to close modal
    if (e.key === 'Escape') {
        closeModal();
    }
});
